const e=`{% block sw_plugin_card %} <div class="sw-plugin-card"> <sw-extension-icon :src="plugin.iconPath" /> <div class="sw-plugin-card__info"> <div class="sw-plugin-card__label"> {{ plugin.label }} </div> <div class="sw-plugin-card__manufacturer"> {{ plugin.manufacturer }} </div> <div v-if="showDescription" class="sw-plugin-card__short-description" > {{ truncateFilter(plugin.shortDescription, 140) }} </div> <div v-if="pluginIsNotActive" class="bottom" > <mt-button variant="primary" :is-loading="pluginIsLoading" :disabled="pluginIsLoading" class="button-plugin-install" @click="onInstall" > {{ $t('sw-first-run-wizard.general.buttonInstall') }} </mt-button> </div> <div v-else class="plugin-status" > <span class="plugin-installed"> <mt-icon name="regular-check-circle-s" size="16" /> {{ $t('sw-first-run-wizard.general.pluginInstalled') }} </span> </div> </div> </div> {% endblock %}`,n=Shopware.Component.wrapComponentConfig({template:e,inject:["cacheApiService","extensionHelperService","shopwareExtensionService"],mixins:[Shopware.Mixin.getByName("sw-extension-error")],props:{plugin:{type:Object,required:!0},showDescription:{type:Boolean,default:!0,required:!1}},data(){return{pluginIsLoading:!1}},computed:{pluginIsNotActive(){return!this.plugin.active},truncateFilter(){return Shopware.Filter.getByName("truncate")}},methods:{onInstall(){this.setupPlugin()},async setupPlugin(){this.pluginIsLoading=!0;try{await this.extensionHelperService.downloadAndActivateExtension(this.plugin.name,this.plugin.type),this.$emit("extension-activated")}catch(i){this.showExtensionErrors(i)}finally{this.pluginIsLoading=!1,this.plugin.type==="plugin"&&this.cacheApiService.clear(),await this.shopwareExtensionService.updateExtensionData(),this.$emit("on-plugin-installed",this.plugin.name)}}}});export{n as default};
